#include <stdio.h>
#include <stdlib.h>

typedef struct { long long pos; int idx; } Soldier;

int cmpSoldier(const void *a, const void *b) {
    Soldier *x = (Soldier *)a, *y = (Soldier *)b;
    if (x->pos != y->pos) return (x->pos < y->pos) ? -1 : 1;
    return (x->idx < y->idx) ? -1 : 1;
}
int cmpLL(const void *a, const void *b) {
    long long x = *(long long *)a, y = *(long long *)b;
    return (x < y) ? -1 : (x > y);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Soldier *sold = (Soldier*)malloc(N * sizeof(Soldier));
        long long *safe = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) { scanf("%lld", &sold[i].pos); sold[i].idx = i; }
        for (int i = 0; i < N; ++i) scanf("%lld", &safe[i]);
        qsort(sold, N, sizeof(Soldier), cmpSoldier);
        qsort(safe, N, sizeof(long long), cmpLL);
        long long *ans = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) ans[sold[i].idx] = safe[i];
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%lld", ans[i]);
        }
        printf("\n");
        free(sold); free(safe); free(ans);
    }
    return 0;
}

