import java.io.*;
import java.util.*;

public class Main {
    private static class Soldier {
        long pos;
        int idx;
        Soldier(long p, int i){ pos=p; idx=i; }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            Soldier[] soldiers = new Soldier[N];
            for (int i = 0; i < N; i++) {
                long p = fs.nextLong();
                soldiers[i] = new Soldier(p, i);
            }
            long[] safe = new long[N];
            for (int i = 0; i < N; i++) safe[i] = fs.nextLong();
            Arrays.sort(soldiers, (a,b)->{
                if (a.pos != b.pos) return Long.compare(a.pos, b.pos);
                return Integer.compare(a.idx, b.idx);
            });
            Arrays.sort(safe);
            long[] ans = new long[N];
            for (int i = 0; i < N; i++) ans[soldiers[i].idx] = safe[i];
            for (int i = 0; i < N; i++) {
                if (i > 0) out.append(' ');
                out.append(ans[i]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
    // Fast scanner for large input
    private static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

