const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  let soldiers = new Array(N);
  for (let i = 0; i < N; ++i) {
    const pos = BigInt(input[idx++]);
    soldiers[i] = {pos, idx: i};
  }
  let safe = new Array(N);
  for (let i = 0; i < N; ++i) safe[i] = BigInt(input[idx++]);
  soldiers.sort((a, b) => {
    if (a.pos < b.pos) return -1;
    if (a.pos > b.pos) return 1;
    return a.idx - b.idx;
  });
  safe.sort((a, b) => (a < b ? -1 : a > b ? 1 : 0));
  let ans = new Array(N);
  for (let i = 0; i < N; ++i) {
    ans[soldiers[i].idx] = safe[i];
  }
  outputs.push(ans.map(v => v.toString()).join(' '));
}
console.log(outputs.join('\n'));

